export function getExercisesForGroup(groupId, equip, level) {
  const diffMap = { beginner:['beg'], intermediate:['beg','int'], advanced:['beg','int','adv'] };
  const allowed = diffMap[level] || ['beg','int'];
  return Object.entries(EXERCISES)
    .filter(([,ex]) => ex.groups?.includes(groupId) && ex.equip.includes(equip) && allowed.includes(ex.diff))
    .map(([id,ex]) => ({ id, ...ex }));
}

export function getCalisthenicsExercises(level) {
  const diffMap = { beginner:['beg'], intermediate:['beg','int'], advanced:['beg','int','adv'] };
  const allowed = diffMap[level] || ['beg','int'];
  return Object.entries(EXERCISES)
    .filter(([,ex]) => ex.tags?.includes('calisthenics') && allowed.includes(ex.diff))
    .map(([id,ex]) => ({ id, ...ex }));
}
